//! Auto-generated by the spec-word-compliance workflow for area
//! **"Run text content and whitespace preservation (t, delText, instrText)"**.
//!
//! Each `#[test]` encodes one declarative TestSpec mined from the OOXML/Word
//! reference (ECMA-376 §17.3.3 run content, XML 1.0 §2.10 character data, and
//! the tracked-change accept/reject rules of §17.13.5). A **FAIL here is a real
//! Word-compliance gap in the stemma engine**, not a flaky test: the assertion
//! message carries the rule text and the spec §refs so the divergence is
//! self-explanatory. Never weaken an assertion to make it pass.
//!
//! Methodology (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim, so `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, not Word's render-time normalization.
//! - `xmlContains` / `xmlRegex` here assert markup the serializer ACTIVELY
//!   re-emits (entity re-escaping from the decoded text model; CT_R / inner
//!   content ORDERING) or structural validity — valid uses.
//! - Consumption semantics ("&amp; reads as &", "sym is one opaque object")
//!   are asserted on the READ side (`read_accepted`/`read_rejected`.`to_text`).

use stemma::api::Document;

// ─── Prelude: minimal-DOCX plumbing (mirrors the shared spec-suite prelude) ──

/// Build a valid minimal `.docx`. `body_xml` is dropped verbatim inside
/// `<w:document …><w:body> … </w:body></w:document>`. `extra_parts` is a list of
/// `(part_name, xml)` written under `word/` (e.g. `("styles.xml", "<…/>")`); a
/// matching `<Override>` is added to `[Content_Types].xml` for each.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-types: defaults + the document override, plus an override per
    // extra part (its content-type keyed by the part filename).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: unknown extra part {other:?} — add its content-type"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, xml) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return the `word/document.xml` of a `.docx`.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    String::from_utf8(
        archive
            .get("word/document.xml")
            .expect("word/document.xml present")
            .to_vec(),
    )
    .expect("document.xml is UTF-8")
}

/// Parse → serialize (ExportOptions::default) → return the serialized
/// `word/document.xml`. For `xml*` expectations: only valid for markup the
/// serializer actively generates/restructures (ordering, escaping, synthesis).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Accept-all read text.
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

/// Reject-all read text.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

/// Opens-clean: `stemma::api::validate` reports no issues.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule} — expected the document to open clean (no validation issues), got {:?}",
        report.issues
    );
}

/// Ordered-substring helper standing in for a regex (the `regex` crate is not a
/// dev-dependency). Asserts each fragment appears in order, left to right.
/// NOTE: this is weaker than the spec's regex (it ignores intervening content),
/// but it still pins the relative ORDER of the named elements, which is the
/// load-bearing claim (CT_R / EG_RunInnerContent sequence).
fn assert_in_order(haystack: &str, fragments: &[&str], rule: &str) {
    let mut cursor = 0usize;
    for frag in fragments {
        match haystack[cursor..].find(frag) {
            Some(rel) => cursor += rel + frag.len(),
            None => panic!(
                "{rule} — expected XML to contain {frag:?} after position {cursor} \
                 (ordered-substring stand-in for the spec regex); full XML:\n{haystack}"
            ),
        }
    }
}

// ─── Tests ────────────────────────────────────────────────────────────────────

/// ECMA-376 §17.3.3.31, XML 1.0 §2.10 — predefined entities decode to literal
/// characters on the read surface.
#[test]
fn t_xml_entity_escapes_unescaped_in_read_text() {
    let rule = "w:t literal text is XML-decoded character data: &amp;/&lt;/&gt; decode to & < > on the read surface (ECMA-376 §17.3.3.31, XML 1.0 §2.10)";
    let b = make_docx(
        r#"<w:p><w:r><w:t xml:space="preserve">A&amp;B&lt;C&gt;D</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "A&B<C>D",
        "{rule} — accept-text: A&amp;B&lt;C&gt;D must read as A&B<C>D"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "A&B<C>D",
        "{rule} — reject-text equals accept (no tracked change present)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.30, Unicode U+FFFC — w:sym is a font-bound special object,
/// surfacing as one U+FFFC, not literal text.
#[test]
fn sym_is_opaque_object_replacement_not_glyph_in_read_text() {
    let rule = "w:sym is a font-bound special character (CT_Empty), not literal w:t text: identity read surface = one U+FFFC, neighbours intact (ECMA-376 §17.3.3.30, Unicode U+FFFC)";
    let b = make_docx(
        r#"<w:p><w:r><w:t xml:space="preserve">X</w:t><w:sym w:font="Wingdings" w:char="F0FC"/><w:t xml:space="preserve">Y</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "X\u{FFFC}Y",
        "{rule} — accept-text: one U+FFFC between preserved X and Y"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "X\u{FFFC}Y",
        "{rule} — reject-text equals accept (sym carries no tracked change)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31 — empty w:t contributes nothing; neighbours concatenate.
#[test]
fn empty_t_contributes_no_text_neighbors_concatenate() {
    let rule = "an empty w:t carries the empty string and adds no characters; adjacent w:t payloads concatenate verbatim with no separator (ECMA-376 §17.3.3.31)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>foo</w:t><w:t></w:t><w:t>bar</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "foobar",
        "{rule} — accept-text: 'foo'+''+'bar' = 'foobar'"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "foobar",
        "{rule} — reject-text equals accept (no tracked change present)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31, XML 1.0 §2.4 — entities decode on read AND re-escape on
/// serialize (stemma rebuilds every w:t from its decoded text model).
#[test]
fn t_text_xml_entities_decode_in_read_and_reescape_on_serialize() {
    let rule = "w:t 'R&amp;D &lt;x&gt;' carries 'R&D <x>' (read decodes); serializer rebuilds w:t from decoded text so save re-escapes as &amp;/&lt;/&gt; (ECMA-376 §17.3.3.31, XML 1.0 §2.4)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>R&amp;D &lt;x&gt;</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "R&D <x>",
        "{rule} — accept-text: predefined entities decode to literal & < >"
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains("R&amp;D &lt;x&gt;"),
        "{rule} — serialized w:t must re-escape literal & < > as &amp;/&lt;/&gt;; got:\n{xml}"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31 — empty w:t between two non-empty siblings reads as 'AB'.
#[test]
fn empty_t_contributes_no_text_and_concatenates_siblings() {
    let rule = "an empty w:t between two non-empty w:t reads as the two payloads concatenated ('AB'), no invented whitespace/glyph (ECMA-376 §17.3.3.31)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:t></w:t><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "AB",
        "{rule} — accept-text: 'A'+''+'B' = 'AB'"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "AB",
        "{rule} — reject-text equals accept (no tracked change present)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31, XML 1.0 §2.10 — whitespace-only preserve run keeps all
/// spaces verbatim into the read surface.
#[test]
fn whitespace_only_t_with_preserve_keeps_all_spaces_in_read_surface() {
    let rule = "a whitespace-only w:t with xml:space='preserve' is significant whitespace: 'A'+'   '(preserve)+'B' reads as 'A   B' with exactly three interior spaces (ECMA-376 §17.3.3.31, XML 1.0 §2.10)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t></w:r><w:r><w:t xml:space="preserve">   </w:t></w:r><w:r><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    // The three spaces are interior (between A and B), so `.trim()` leaves them.
    assert_eq!(
        accept_text(&b).trim(),
        "A   B",
        "{rule} — accept-text: three preserved interior spaces survive"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "A   B",
        "{rule} — reject-text equals accept (no tracked change present)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31, XML 1.0 §2.10, §A.1 CT_Text — predefined entities
/// decode on read and the serializer re-escapes (no raw &/<, no double-escape).
#[test]
fn xml_predefined_entities_in_t_roundtrip() {
    let rule = "w:t predefined entities (&amp; &lt; &gt;) decode to & < > on read; serializer re-emits & and < as escapes, never raw, never double-escaped (ECMA-376 §17.3.3.31, XML 1.0 §2.10, §A.1 CT_Text)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>a &amp; b &lt; c &gt; d</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "a & b < c > d",
        "{rule} — accept-text: entities decode to literal characters"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3, §A.1 CT_R, §17.3.2.28 — w:rPr serializes before run inner
/// content (CT_R sequence: EG_RPr then EG_RunInnerContent).
#[test]
fn rpr_precedes_run_inner_content() {
    let rule = "CT_R is EG_RPr (once) then EG_RunInnerContent: w:rPr must serialize before w:t within the run (ECMA-376 §17.3.3, §A.1 CT_R, §17.3.2.28)";
    let b = make_docx(
        r#"<w:p><w:r><w:rPr><w:b/></w:rPr><w:t>bold text</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    // Regex stand-in: <w:rPr> … </w:rPr> … <w:t …>bold text</w:t> in order.
    let xml = reserialize(&b);
    assert_in_order(
        &xml,
        &["<w:rPr>", "</w:rPr>", "<w:t", "bold text", "</w:t>"],
        rule,
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3 / §17.3.3.31 / §17.3.3.32 / §A.1 EG_RunInnerContent —
/// heterogeneous run inner content keeps authored document order (t, tab, t),
/// not reordered or coalesced.
#[test]
fn mixed_run_content_document_order_preserved() {
    let rule = "EG_RunInnerContent is an ordered repeating choice: t/tab/t serialize in authored order and the two text fragments do not coalesce across the tab (ECMA-376 §17.3.3, §17.3.3.31, §17.3.3.32, §A.1 EG_RunInnerContent)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:tab/><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    let xml = reserialize(&b);
    assert_in_order(
        &xml,
        &["<w:t", "A", "</w:t>", "<w:tab/>", "<w:t", "B", "</w:t>"],
        rule,
    );
    assert_eq!(
        accept_text(&b).trim(),
        "A\tB",
        "{rule} — accept-text: w:tab is U+0009 between the two fragments"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.7 / §17.3.3.31 / §17.13.5.14, XML 1.0 §2.10 — live preserve
/// trailing space + deleted delText preserve spaces, across accept/reject.
#[test]
fn deltext_preserve_whitespace_concatenates_with_live_run_on_reject() {
    let rule = "live w:t trailing preserve-space + deleted delText leading preserve-space: reject re-joins both preserved fragments, accept drops exactly the delText leaving the live trailing space (ECMA-376 §17.3.3.7, §17.3.3.31, §17.13.5.14, XML 1.0 §2.10)";
    let b = make_docx(
        r#"<w:p><w:r><w:t xml:space="preserve">left </w:t></w:r><w:del w:id="1" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:delText xml:space="preserve"> mid </w:delText></w:r></w:del><w:r><w:t>right</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        reject_text(&b).trim(),
        "left  mid right",
        "{rule} — reject-text: 'left ' + ' mid ' + 'right' = 'left  mid right'"
    );
    assert_eq!(
        accept_text(&b).trim(),
        "left right",
        "{rule} — accept-text: drop ' mid ', keep live trailing space = 'left right'"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.31, XML 1.0 §2.10 — whitespace surrounding a typed
/// enumeration label is SIGNIFICANT and must round-trip verbatim. The importer
/// hoists the label `c.` into `literal_prefix`, but the leading indentation and
/// the multi-space separator around the label are real run content: a styles-only
/// reserialize (the prod re-skin path) must re-emit every space.
///
/// Regression: the literal-prefix extractor discretized the stripped whitespace
/// to a tab-count + boolean, dropping leading spaces and collapsing the separator
/// to a single space (XL re-skin: −893 significant-space chars). The model now
/// carries the verbatim leading/trailing whitespace and the serializer re-emits it.
#[test]
fn literal_prefix_surrounding_whitespace_survives_reserialize() {
    let rule = "leading indentation and the multi-space separator around a typed enumeration label are significant whitespace and must round-trip verbatim through a styles-only reserialize (ECMA-376 §17.3.3.31, XML 1.0 §2.10)";
    // "   c.   p-value" — 3 leading spaces, label `c.`, 3 separator spaces.
    let b = make_docx(
        r#"<w:p><w:r><w:t xml:space="preserve">   c.   p-value follows</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    // NB: the read/accept surface RENDERS the label with a synthesized tab
    // separator (`c.\tp-value …`) — that is the intentional read projection, not
    // the verbatim body. The verbatim-whitespace contract is asserted on the
    // SERIALIZE side below (what the re-skin path writes back to Word).
    // The serialized w:t content (concatenated) must contain the full
    // "   c.   p-value" with both 3-space runs intact.
    let xml = reserialize(&b);
    let t_text: String = {
        // crude: pull every <w:t ...>…</w:t> payload and join
        let mut out = String::new();
        let mut rest = xml.as_str();
        while let Some(open) = rest.find("<w:t") {
            rest = &rest[open..];
            let Some(gt) = rest.find('>') else { break };
            // skip self-closing or non-text (<w:tab/>) — only real <w:t> open tags
            if rest[..gt].contains("/") {
                rest = &rest[gt + 1..];
                continue;
            }
            let after = &rest[gt + 1..];
            let Some(close) = after.find("</w:t>") else {
                break;
            };
            out.push_str(&after[..close]);
            rest = &after[close + 6..];
        }
        out
    };
    assert!(
        t_text.contains("   c.") && t_text.contains("c.   p-value"),
        "{rule} — serialized text must preserve BOTH the 3-space leading indent and \
         the 3-space separator; got concatenated w:t = {t_text:?}\nfull XML:\n{xml}"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.22, Unicode U+FFFC — w:pgNum is a legacy field-like marker:
/// one U+FFFC on the identity read surface, no stored digit text.
#[test]
fn pgnum_block_is_opaque_barrier_not_literal_text() {
    let rule = "w:pgNum is a non-editable legacy field-like marker (CT_Empty): identity read = one U+FFFC, no literal digit, surrounding prose preserved, reject==accept (ECMA-376 §17.3.3.22, Unicode U+FFFC)";
    let b = make_docx(
        r#"<w:p><w:r><w:t xml:space="preserve">Page </w:t><w:pgNum/><w:t xml:space="preserve"> end</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "Page \u{FFFC} end",
        "{rule} — accept-text: one U+FFFC between preserved 'Page ' and ' end'"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Page \u{FFFC} end",
        "{rule} — reject-text equals accept (pgNum carries no tracked change)"
    );
    assert_opens_clean(&b, rule);
}

/// ECMA-376 §17.3.3.23 / §17.3.3.32, Unicode U+FFFC — w:ptab (absolute-position
/// tab) is a positioning object (one U+FFFC), distinct from w:tab (U+0009).
#[test]
fn ptab_is_opaque_barrier_distinct_from_tab() {
    let rule = "w:ptab (absolute-position tab) is a positioning object surfacing as one U+FFFC, NOT the §17.3.3.32 w:tab=U+0009; neighbours intact (ECMA-376 §17.3.3.23, §17.3.3.32, Unicode U+FFFC)";
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:ptab w:alignment="center" w:relativeTo="margin" w:leader="none"/><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_eq!(
        accept_text(&b).trim(),
        "A\u{FFFC}B",
        "{rule} — accept-text: one U+FFFC between literal A and B"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "A\u{FFFC}B",
        "{rule} — reject-text equals accept (ptab carries no tracked change)"
    );
    assert_opens_clean(&b, rule);
}
